function greet(name) {
  // 引数のnameを使って挨拶文を作成し、それをconsole.logで出力
  console.log('Hello, ' + name + '!');
}

// functionを実行
// console.logで 'Hello, Alice!' と表示

greet('Alice');

function add(a, b) {
  // 引数aとbを加算し、その結果をconsole.logで出力
  console.log(a + b);
}

// functionを実行
// console.logで '15' と表示

add(7, 8);

function introduce(name = 'unknown', age = 'unknown') {
  // 引数のnameとageを使って自己紹介文を作成し、それをconsole.logで出力
  console.log('Hello, I\'m ' + name + ' and I am ' + age + ' years old.');
}

// functionを実行
// console.logで 'Hello, I\'m Bob and I am 25 years old.' と表示

introduce('Bob', 25);

function sum(...nums) {
  // 引数numsを全て加算する
  let total = 0;
  for(let num of nums) {
    total += num;
  }

  // 合計値をconsole.logで出力
  console.log(total);
}

// functionを実行
// console.logで '10' と表示

sum(1, 2, 3, 4);

let outsideVar = 'Outside';

function testArgScope(arg) {
  console.log('Before changing: ', arg);
  arg = 'Inside';
  console.log('After changing: ', arg);
}

// functionを実行
// console.logで 'Before changing: Outside' と 'After changing: Inside' と表示

testArgScope(outsideVar);

// 外部での変数の値を表示
// console.logで 'Outside' と表示
console.log('Outside after function: ', outsideVar);

let person = {name: 'Alice', age: 20};

function changeProperty(obj) {
  console.log('Before changing: ', obj);
  obj.name = 'Bob';
  console.log('After changing: ', obj);
}

// functionを実行
// console.logで 'Before changing: {name: 'Alice', age: 20}' と 'After changing: {name: 'Bob', age: 20}' と表示

changeProperty(person);

// 外部でのオブジェクトの値を表示
// console.logで '{name: 'Bob', age: 20}' と表示
console.log('Outside after function: ', person);

function addWithDefault(num1, num2 = 10) {
  let result = num1 + num2;
  console.log('Result: ', result);
}

// functionを実行
// console.logで 'Result: 15' と表示

addWithDefault(5);

// functionを実行
// console.logで 'Result: 8' と表示

addWithDefault(3, 5);

function sum(...nums) {
  let total = 0;
  for (let num of nums) {
    total += num;
  }
  console.log('Total: ', total);
}

// functionを実行
// console.logで 'Total: 10' と表示

sum(1, 2, 3, 4);

function checkScope(x) {
  var x = 2;
  console.log('Value inside function: ', x);
}

let x = 1;

console.log('Value outside function: ', x);
// console.logで 'Value outside function: 1' と表示

checkScope(x);
// console.logで 'Value inside function: 2' と表示

